from collections import Counter
class Solution:
    def minCost(self, nums, k):
        n = len(nums)
        memo = {}
        def trimmed_cost(i, j):
            cnt = Counter(nums[i:j + 1])
            return sum(v for v in cnt.values() if v >= 2)
        def dp(i):
            if i == n:
                return 0
            if i in memo:
                return memo[i]
            best = None
            for j in range(i, n):
                cand = k + trimmed_cost(i, j) + dp(j + 1)
                if best is None or cand < best:
                    best = cand
            memo[i] = best
            return best
        return dp(0)

