class Solution:
    def minCost(self, nums, k):
        n = len(nums)
        dp = [0] + [float('inf')] * n
        for i in range(n):
            freq = {}
            trimmed = 0
            for j in range(i, -1, -1):
                x = nums[j]
                c = freq.get(x, 0)
                if c == 1:
                    trimmed += 2
                elif c >= 2:
                    trimmed += 1
                freq[x] = c + 1
                cand = dp[j] + k + trimmed
                if cand < dp[i + 1]:
                    dp[i + 1] = cand
        return dp[n]

