var minCost = function(nums, k) {
    const n = nums.length;
    const dp = new Array(n + 1).fill(Infinity);
    dp[0] = 0;
    for (let i = 0; i < n; i++) {
        const freq = new Map();
        let trimmed = 0;
        for (let j = i; j >= 0; j--) {
            const x = nums[j];
            const c = freq.get(x) || 0;
            if (c === 1) trimmed += 2;
            else if (c >= 2) trimmed += 1;
            freq.set(x, c + 1);
            const cand = dp[j] + k + trimmed;
            if (cand < dp[i + 1]) dp[i + 1] = cand;
        }
    }
    return dp[n];
};
